if ($_SERVER['REQUEST_METHOD'] === 'POST' && isset($_POST['ciphertext'])) {
    $input_ciphertext = $_POST['ciphertext'] ?? '';
    
    // 1. Clean the input (remove spaces, newlines, and non-hex characters)
    $clean_hex = preg_replace('/[^0-9a-fA-F]/', '', $input_ciphertext);
    
    // 2. Validate hex string length
    if (empty($clean_hex)) {
        $error_msg = "Error: Input is empty or contains no valid Hex characters.";
    } elseif (strlen($clean_hex) % 2 !== 0) {
        $error_msg = "Error: Invalid Hex string length (must be an even number of characters).";
    } else {
        // Convert hex back to binary string bytes
        $binary_data = hex2bin($clean_hex);
        $data_length = strlen($binary_data);
        
        // 3. Automated Brute-Force: Test all 256 possible byte keys
        for ($key = 0; $key < 256; $key++) {
            $decrypted_string = "";
            
            // XOR operation
