                $decrypted_string .= chr(ord($binary_data[$i]) ^ $key);
            }
            
            // 4. Intelligent Flag Matcher (checks common CTF patterns case-insensitively)
            if (preg_match('/(flag|ctf|hidden|pico|sec|key)\s*\{/i', $decrypted_string)) {
                $cracked_flag = htmlspecialchars($decrypted_string, ENT_SUBSTITUTE, 'UTF-8');
                $used_key = $key . " (0x" . strtoupper(str_pad(dechex($key), 2, '0', STR_PAD_LEFT)) . ")";
                break; // Stop looking once the flag format is matched
            }
        }
        
        // Fallback: If no common flag pattern is found, show the best guess or top keys
        if (empty($cracked_flag)) {
            $error_msg = "No clear CTF flag format found. Double-check your ciphertext or try manual extraction.";
        }
    }
}
